package allstar

import (
	"fmt"
	"strings"

	"typefox.dev/fastbelt/generator"
)

// EmitATNFunc returns a generator Node containing a single ATN constructor
// function definition — no package declaration or import statement.  The
// returned node can be embedded directly into a larger generated file that
// already imports the allstar package.
//
//   funcName    – name of the generated function (e.g. "buildATN")
//   importAlias – the local alias used for the allstar package in the
//                 consuming file's import block (e.g. "allstar")
func EmitATNFunc(funcName, importAlias string, rtn *RuntimeATN) generator.Node {
	idx := make(map[*RuntimeATNState]int, len(rtn.States))
	for i, s := range rtn.States {
		idx[s] = i
	}
	a := importAlias + "."
	root := generator.NewNode()
	root.AppendLine("func ", funcName, "() *", a, "RuntimeATN {")
	root.Indent(func(body generator.Node) {
		emitATNBody(body, a, idx, rtn)
	})
	root.AppendLine("}")
	return root
}

// EmitGoSource returns Go source code for a self-contained file that declares
// an ATN constructor function.  The generated function can be compiled into
// any package that imports the allstar package.
//
//   pkgName    – Go package name for the generated file (e.g. "myparser")
//   funcName   – name of the generated constructor function
//   importPath – import path of the allstar package
func EmitGoSource(pkgName, funcName, importPath string, rtn *RuntimeATN) string {
	root := generator.NewNode()
	root.AppendLine("// Code generated by fastbelt. DO NOT EDIT.")
	root.AppendLine()
	root.AppendLine("package ", pkgName)
	root.AppendLine()
	root.AppendLine(fmt.Sprintf("import allstar %q", importPath))
	root.AppendLine()
	root.AppendNode(EmitATNFunc(funcName, "allstar", rtn))
	root.AppendLine()
	return root.String()
}

// emitATNBody writes the body of an ATN constructor into body.
// a is the qualified prefix for allstar types (e.g. "allstar.").
func emitATNBody(body generator.Node, a string, idx map[*RuntimeATNState]int, rtn *RuntimeATN) {
	body.AppendLine(fmt.Sprintf("states := make([]*%sRuntimeATNState, %d)", a, len(rtn.States)))

	// Emit state declarations (without transitions so forward refs are fine).
	for i, s := range rtn.States {
		body.AppendLine(fmt.Sprintf("states[%d] = &%sRuntimeATNState{", i, a))
		body.Indent(func(fields generator.Node) {
			fields.AppendLine(fmt.Sprintf("StateNumber: %d,", s.StateNumber))
			fields.AppendLine(fmt.Sprintf("Type: %s%s,", a, atnStateTypeName(s.Type)))
			fields.AppendLine(fmt.Sprintf("Decision: %d,", s.Decision))
			if s.EpsilonOnlyTransitions {
				fields.AppendLine("EpsilonOnlyTransitions: true,")
			}
			if s.RuleName != "" {
				fields.AppendLine(fmt.Sprintf("RuleName: %q,", s.RuleName))
			}
			if s.ProdIdx != 0 {
				fields.AppendLine(fmt.Sprintf("ProdKind: %s%s,", a, productionKindName(s.ProdKind)))
				fields.AppendLine(fmt.Sprintf("ProdIdx: %d,", s.ProdIdx))
			}
		})
		body.AppendLine("}")
	}

	// Emit transitions (states already declared, so pointer refs are valid).
	for i, s := range rtn.States {
		if len(s.Transitions) == 0 {
			continue
		}
		body.AppendLine(fmt.Sprintf("states[%d].Transitions = []%sRuntimeTransition{", i, a))
		body.Indent(func(trans generator.Node) {
			for _, t := range s.Transitions {
				switch at := t.(type) {
				case *RuntimeAtomTransition:
					trans.AppendLine(fmt.Sprintf(
						"&%sRuntimeAtomTransition{Target: states[%d], TokenTypeID: %d, CategoryMatches: %s},",
						a, idx[at.Target], at.TokenTypeID, emitIntSlice(at.CategoryMatches)))
				case *RuntimeEpsilonTransition:
					trans.AppendLine(fmt.Sprintf(
						"&%sRuntimeEpsilonTransition{Target: states[%d]},",
						a, idx[at.Target]))
				case *RuntimeRuleTransition:
					trans.AppendLine(fmt.Sprintf(
						"&%sRuntimeRuleTransition{Target: states[%d], FollowState: states[%d]},",
						a, idx[at.Target], idx[at.FollowState]))
				}
			}
		})
		body.AppendLine("}")
	}

	// DecisionStates slice.
	body.AppendLine(fmt.Sprintf("decisionStates := make([]*%sRuntimeATNState, %d)", a, len(rtn.DecisionStates)))
	for i, ds := range rtn.DecisionStates {
		if ds != nil {
			body.AppendLine(fmt.Sprintf("decisionStates[%d] = states[%d]", i, idx[ds]))
		}
	}

	// DecisionMap.
	body.AppendLine(fmt.Sprintf("decisionMap := map[string]*%sRuntimeATNState{", a))
	body.Indent(func(entries generator.Node) {
		for key, s := range rtn.DecisionMap {
			entries.AppendLine(fmt.Sprintf("%q: states[%d],", key, idx[s]))
		}
	})
	body.AppendLine("}")

	body.AppendLine(fmt.Sprintf("return &%sRuntimeATN{", a))
	body.Indent(func(fields generator.Node) {
		fields.AppendLine("States:         states,")
		fields.AppendLine("DecisionStates: decisionStates,")
		fields.AppendLine("DecisionMap:    decisionMap,")
	})
	body.AppendLine("}")
}

func emitIntSlice(s []int) string {
	if len(s) == 0 {
		return "nil"
	}
	parts := make([]string, len(s))
	for i, v := range s {
		parts[i] = fmt.Sprintf("%d", v)
	}
	return "[]int{" + strings.Join(parts, ", ") + "}"
}

func atnStateTypeName(t ATNStateType) string {
	switch t {
	case ATNInvalidType:
		return "ATNInvalidType"
	case ATNBasic:
		return "ATNBasic"
	case ATNRuleStart:
		return "ATNRuleStart"
	case ATNPlusBlockStart:
		return "ATNPlusBlockStart"
	case ATNStarBlockStart:
		return "ATNStarBlockStart"
	case ATNTokenStart:
		return "ATNTokenStart"
	case ATNRuleStop:
		return "ATNRuleStop"
	case ATNBlockEnd:
		return "ATNBlockEnd"
	case ATNStarLoopBack:
		return "ATNStarLoopBack"
	case ATNStarLoopEntry:
		return "ATNStarLoopEntry"
	case ATNPlusLoopBack:
		return "ATNPlusLoopBack"
	case ATNLoopEnd:
		return "ATNLoopEnd"
	default:
		return fmt.Sprintf("ATNStateType(%d)", int(t))
	}
}

func productionKindName(k ProductionKind) string {
	switch k {
	case ProdTerminal:
		return "ProdTerminal"
	case ProdNonTerminal:
		return "ProdNonTerminal"
	case ProdAlternative:
		return "ProdAlternative"
	case ProdAlternation:
		return "ProdAlternation"
	case ProdOption:
		return "ProdOption"
	case ProdRepetition:
		return "ProdRepetition"
	case ProdRepetitionMandatory:
		return "ProdRepetitionMandatory"
	default:
		return fmt.Sprintf("ProductionKind(%d)", int(k))
	}
}
